#!/usr/bin/env python3
"""
Dos mejoras:

1) El bot ahora conoce el horario de atencion del negocio (tabla
   'schedules', fila general sin staff_id) y responde directamente
   preguntas sobre horarios, en vez de derivarlas al negocio.

2) Se loguean los webhooks de 'status' de WhatsApp (sent/delivered/
   read/failed) como '[whatsapp-status] ...', incluyendo el motivo
   de error si una imagen de show_services falla en la entrega
   aunque la API la haya aceptado al enviarla.

Ejecutar desde la raiz del repo (carpeta que contiene 'src'):
    python3 apply_whatsapp_bot_schedule_and_status_logs.py
"""

import base64
from pathlib import Path

FILES = {
    'src/lib/whatsappBot.ts': """""",
    'src/app/api/whatsapp/webhook/route.ts': """""",
}

def main():
    for relpath, b64 in FILES.items():
        p = Path(relpath)
        p.write_bytes(base64.b64decode(b64))
        print(f"escrito: {relpath} ({p.stat().st_size} bytes)")
    print()
    print("Listo. Luego:")
    print("  git add -A")
    print("  git commit -m 'Bot de WhatsApp: horario de atencion + logs de estado de entrega'")
    print("  git push")

if __name__ == "__main__":
    main()